+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {kind: 'fixed'; size: number}
+	| {kind: 'fr'; value: number}
+	| {kind: 'auto'}
+	| {kind: 'minmax'; min: number; max: number | {fr: number}};
+
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const splitTracks = (template: string): string[] => {
+	const tracks: string[] = [];
+	let depth = 0;
+	let token = '';
+
+	for (const character of template.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+		if (/\\s/.test(character) && depth === 0) {
+			if (token) tracks.push(token);
+			token = '';
+		} else {
+			token += character;
+		}
+	}
+
+	if (token) tracks.push(token);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {kind: 'auto'};
+	const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fr) return {kind: 'fr', value: Number(fr[1])};
+	const minmax = /^minmax\\((\\d*\\.?\\d+),\\s*(\\d*\\.?\\d+|\\d*\\.?\\d+fr)\\)$/.exec(value);
+	if (minmax) {
+		const maximum = minmax[2]!.endsWith('fr')
+			? {fr: Number.parseFloat(minmax[2]!)}
+			: Number.parseFloat(minmax[2]!);
+		return {kind: 'minmax', min: Number.parseFloat(minmax[1]!), max: maximum};
+	}
+
+	const size = Number.parseFloat(value);
+	if (!Number.isNaN(size) && /^\\d*\\.?\\d+$/.test(value)) return {kind: 'fixed', size};
+	throw new Error(`Invalid grid track size: ${value}`);
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	template ? splitTracks(template).map(parseTrack) : [];
+
+const parseLine = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value - 1, value];
+	if (!value) return undefined;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+	if (!match) throw new Error(`Invalid grid line: ${value}`);
+	const start = Number(match[1]) - 1;
+	const end = Number(match[2]) - 1;
+	if (start < 0 || end <= start) throw new Error(`Invalid grid line: ${value}`);
+	return [start, end];
+};
+
+const overlaps = (a: Placement, b: Placement): boolean =>
+	a.column < b.columnEnd && a.columnEnd > b.column && a.row < b.rowEnd && a.rowEnd > b.row;
+
+const placeItems = (children: DOMElement[], columns: number): Placement[] => {
+	const placements: Placement[] = [];
+	for (const child of children) {
+		const columnLine = parseLine(child.style.gridColumn);
+		const rowLine = parseLine(child.style.gridRow);
+		let placement: Placement | undefined;
+		const columnSpan = columnLine ? columnLine[1] - columnLine[0] : 1;
+		const rowSpan = rowLine ? rowLine[1] - rowLine[0] : 1;
+		if (columnLine && columnLine[1] > columns) {
+			throw new Error('gridColumn references a column outside gridTemplateColumns');
+		}
+
+		for (let row = rowLine?.[0] ?? 0; !placement; row++) {
+			if (rowLine && row !== rowLine[0]) break;
+			for (let column = columnLine?.[0] ?? 0; column <= columns - columnSpan; column++) {
+				if (columnLine && column !== columnLine[0]) break;
+				const candidate = {column, columnEnd: column + columnSpan, row, rowEnd: row + rowSpan};
+				if (!placements.some(existing => overlaps(existing, candidate))) {
+					placement = candidate;
+					break;
+				}
+			}
+		}
+
+		placements.push(placement!);
+	}
+	return placements;
+};
+
+const resolveTracks = (tracks: Track[], available: number, gap: number, autoSizes: number[]): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.kind === 'fixed') return track.size;
+		if (track.kind === 'auto') return autoSizes[index] ?? 0;
+		if (track.kind === 'minmax') return track.min;
+		return 0;
+	});
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - sizes.reduce((sum, size) => sum + size, 0));
+	const fraction = tracks.reduce((sum, track) => sum + (track.kind === 'fr' ? track.value : track.kind === 'minmax' && typeof track.max !== 'number' ? track.max.fr : 0), 0);
+	if (fraction > 0) {
+		tracks.forEach((track, index) => {
+			if (track.kind === 'fr') sizes[index] = remaining * track.value / fraction;
+			if (track.kind === 'minmax' && typeof track.max !== 'number') sizes[index] += remaining * track.max.fr / fraction;
+		});
+	}
+	tracks.forEach((track, index) => {
+		if (track.kind === 'minmax' && typeof track.max === 'number') sizes[index] = track.max;
+	});
+	return sizes;
+};
+
+const positions = (sizes: number[], gap: number): number[] => {
+	let offset = 0;
+	return sizes.map(size => {
+		const position = offset;
+		offset += size + gap;
+		return position;
+	});
+};
+
+const gridChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+
+const layoutGrid = (node: DOMElement): boolean => {
+	if (node.style.display !== 'grid' || !node.yogaNode) return false;
+	const children = gridChildren(node);
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	const columnTracks = columns.length > 0 ? columns : [{kind: 'auto'} satisfies Track];
+	const placements = placeItems(children, columnTracks.length);
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const layout = node.yogaNode.getComputedLayout();
+	const horizontalPadding = node.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + node.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) + node.yogaNode.getComputedBorder(Yoga.EDGE_LEFT) + node.yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const verticalPadding = node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) + node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) + node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const autoColumnSizes = columnTracks.map((_, index) => Math.max(0, ...children.filter((_, childIndex) => placements[childIndex]!.column === index && placements[childIndex]!.columnEnd === index + 1).map(child => child.yogaNode!.getComputedLayout().width)));
+	const columnSizes = resolveTracks(columnTracks, Math.max(0, layout.width - horizontalPadding), columnGap, autoColumnSizes);
+	const columnPositions = positions(columnSizes, columnGap);
+	const explicitRows = parseTracks(node.style.gridTemplateRows);
+	const rowCount = Math.max(explicitRows.length, ...placements.map(placement => placement.rowEnd), 0);
+	const rowTracks = Array.from({length: rowCount}, (_, index) => explicitRows[index] ?? ({kind: 'auto'} satisfies Track));
+	const autoRowSizes = rowTracks.map((_, index) => Math.max(0, ...children.filter((_, childIndex) => placements[childIndex]!.row === index && placements[childIndex]!.rowEnd === index + 1).map(child => child.yogaNode!.getComputedLayout().height)));
+	const availableHeight = Math.max(0, layout.height - verticalPadding);
+	const rowSizes = resolveTracks(rowTracks, availableHeight, rowGap, autoRowSizes);
+	const rowPositions = positions(rowSizes, rowGap);
+	const implicitHeight = rowSizes.reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, rowSizes.length - 1) + verticalPadding;
+	if (node.style.height === undefined) node.yogaNode.setHeight(implicitHeight);
+
+	children.forEach((child, index) => {
+		const placement = placements[index]!;
+		const width = columnSizes.slice(placement.column, placement.columnEnd).reduce((sum, size) => sum + size, 0) + columnGap * (placement.columnEnd - placement.column - 1);
+		const height = rowSizes.slice(placement.row, placement.rowEnd).reduce((sum, size) => sum + size, 0) + rowGap * (placement.rowEnd - placement.row - 1);
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnPositions[placement.column]!);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowPositions[placement.row]!);
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height || undefined);
+	});
+
+	return true;
+};
+
+const visit = (node: DOMNode): boolean => {
+	if (node.nodeName === '#text') return false;
+	let found = layoutGrid(node);
+	for (const child of node.childNodes) found = visit(child) || found;
+	return found;
+};
+
+export const calculateGridLayout = (root: DOMElement): void => {
+	// The first Yoga pass supplies available sizes. Two grid passes then measure auto
+	// tracks and apply the resulting rectangles, including nested grids.
+	if (visit(root)) {
+		root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+		visit(root);
+		root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	}
+};
