import {act} from 'react';
import {render} from '../../src/index.js';
import createStdout from './create-stdout.js';

type RenderToStringOptions = {
	columns?: number;
	isScreenReaderEnabled?: boolean;
};

/**
Synchronous render to string (legacy mode).
*/
export const renderToString: (
	node: React.JSX.Element,
	options?: RenderToStringOptions,
) => string = (node, options) => {
	const stdout = createStdout(options?.columns ?? 100);

	render(node, {
		stdout,
		debug: true,
		isScreenReaderEnabled: options?.isScreenReaderEnabled,
	});

	const output = stdout.get();
	return output;
};

/**
Async render to string with concurrent mode support.

Uses `act()` to properly flush updates.
*/
export const renderToStringAsync: (
	node: React.JSX.Element,
	options?: RenderToStringOptions,
) => Promise<string> = async (node, options) => {
	const stdout = createStdout(options?.columns ?? 100);

	await act(async () => {
		render(node, {
			stdout,
			debug: true,
			isScreenReaderEnabled: options?.isScreenReaderEnabled,
			concurrent: true,
		});
	});

	const output = stdout.get();
	return output;
};
import EventEmitter from 'node:events';
import {spy} from 'sinon';

// Fake process.stdout
export type FakeStdout = {
	get: () => string;
	getWrites: () => string[];
} & NodeJS.WriteStream;

const createStdout = (columns?: number, isTTY?: boolean): FakeStdout => {
	const stdout = new EventEmitter() as unknown as FakeStdout;
	stdout.columns = columns ?? 100;
	stdout.isTTY = isTTY ?? true;

	const write = spy();
	stdout.write = write;

	stdout.get = () => write.lastCall.args[0] as string;

	stdout.getWrites = () => (write.args as string[][]).map(args => args[0]!);

	return stdout;
};

export default createStdout;
